package arch.day34;

public class Day34Intermediate {
    static int count = 0;
    static final Object lock = new Object();

    public static void main(String[] args) throws Exception {
        Thread a = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                synchronized (lock) { count++; }
            }
        });
        Thread b = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                synchronized (lock) { count++; }
            }
        });
        a.start(); b.start();
        a.join(); b.join();
        System.out.println(count);
    }
}

